library(tidyplots)

# Get current year
current_year &lt;- format(Sys.Date(), "%Y") |&gt; 
  as.numeric()

# Stages
tag &lt;- c("pre-school", "school", "academia", "out of academia")
years_young = c(5, 24, 9, current_year - 2021)

# A data frame
df &lt;- tibble::tibble(
  years_young = years_young,
  tag = factor(
    x = tag,
    level = tag
  )
)

# Plot
df |&gt; 
  tidyplot(
    x = years_young, 
    color = tag) |&gt; 
  add_barstack_absolute() |&gt;   
  add_caption(caption = paste("as of", current_year)) |&gt; 
  adjust_size(
    width = 100, 
    height = 10) |&gt; 
  adjust_legend_position(position = "top") |&gt; 
  reverse_color_levels() |&gt; 
  remove_legend_title() |&gt; 
  remove_y_axis_title() |&gt; 
  remove_y_axis_ticks() |&gt; 
  save_plot(
    filename = "images/wk_barstack-absolute.png",
    view_plot = FALSE)
